/**
 * Object containing the allowed connector fields, which varies according to the connector type.
 *
 * For Slack:
 *
 * - `message` (string, required): The notification message.
 *
 * For email:
 *
 * - `to`, `cc`, `bcc` (string): Email addresses to which the notifications are sent. At least one field must have a value.
 * - `subject` (string, optional): Email subject line.
 * - `message` (string, required): Email body text.
 *
 * For Webhook:
 *
 * - `body` (string, required): JSON payload.
 *
 * For PagerDuty:
 *
 * - `severity` (string, required): Severity of on the alert notification, can be: `Critical`, `Error`, `Warning` or `Info`.
 * - `eventAction` (string, required): Event [action type](https://v2.developer.pagerduty.com/docs/events-api-v2#event-action), which can be `trigger`, `resolve`, or `acknowledge`.
 * - `dedupKey` (string, optional): Groups alert notifications with the same PagerDuty alert.
 * - `timestamp` (DateTime, optional): ISO-8601 format [timestamp](https://v2.developer.pagerduty.com/docs/types#datetime).
 * - `component` (string, optional): Source machine component responsible for the event, for example `security-solution`.
 * - `group` (string, optional): Enables logical grouping of service components.
 * - `source` (string, optional): The affected system. Defaults to the Kibana saved object ID of the action.
 * - `summary` (string, options): Summary of the event. Defaults to `No summary provided`. Maximum length is 1024 characters.
 * - `class` (string, optional): Value indicating the class/type of the event.
 *
 */
export const security_detections_api_rule_action_params = z.record(z.string(), z.unknown()).register(z.globalRegistry, {
    description: 'Object containing the allowed connector fields, which varies according to the connector type.\n\nFor Slack:\n\n  - `message` (string, required): The notification message.\n\nFor email:\n\n  - `to`, `cc`, `bcc` (string): Email addresses to which the notifications are sent. At least one field must have a value.\n  - `subject` (string, optional): Email subject line.\n  - `message` (string, required): Email body text.\n\nFor Webhook:\n\n  - `body` (string, required): JSON payload.\n\nFor PagerDuty:\n\n  - `severity` (string, required): Severity of on the alert notification, can be: `Critical`, `Error`, `Warning` or `Info`.\n  - `eventAction` (string, required): Event [action type](https://v2.developer.pagerduty.com/docs/events-api-v2#event-action), which can be `trigger`, `resolve`, or `acknowledge`.\n  - `dedupKey` (string, optional): Groups alert notifications with the same PagerDuty alert.\n  - `timestamp` (DateTime, optional): ISO-8601 format [timestamp](https://v2.developer.pagerduty.com/docs/types#datetime).\n  - `component` (string, optional): Source machine component responsible for the event, for example `security-solution`.\n  - `group` (string, optional): Enables logical grouping of service components.\n  - `source` (string, optional): The affected system. Defaults to the Kibana saved object ID of the action.\n  - `summary` (string, options): Summary of the event. Defaults to `No summary provided`. Maximum length is 1024 characters.\n  - `class` (string, optional): Value indicating the class/type of the event.\n'
});

