/**
 * Object containing an action’s conditional filters.
 *
 * - `timeframe` (object, optional): Object containing the time frame for when this action can be run.
 * - `days` (array of integers, required): List of days of the week on which this action will be run. Days of the week are expressed as numbers between `1-7`, where `1` is Monday and `7` is Sunday. To select all days of the week, enter an empty array.
 * - `hours` (object, required): The hours of the day during which this action will run. Hours of the day are expressed as two strings in the format `hh:mm` in `24` hour time. A start of `00:00` and an end of `24:00` means the action can run all day.
 * - start (string, required): Start time in `hh:mm` format.
 * - end (string, required): End time in `hh:mm` format.
 * - `timezone` (string, required): An ISO timezone name, such as `Europe/Madrid` or `America/New_York`. Specific offsets such as `UTC` or `UTC+1` will also work, but lack built-in DST.
 * - `query` (object, optional): Object containing a query filter which gets applied to an action and determines whether the action should run.
 * - `kql` (string, required): A KQL string.
 * - `filters` (array of objects, required): Array of filter objects, as defined in the `kbn-es-query` package.
 *
 */
export const security_detections_api_rule_action_alerts_filter = z.record(z.string(), z.unknown()).register(z.globalRegistry, {
    description: 'Object containing an action’s conditional filters.\n\n- `timeframe` (object, optional): Object containing the time frame for when this action can be run.\n    - `days` (array of integers, required): List of days of the week on which this action will be run. Days of the week are expressed as numbers between `1-7`, where `1` is Monday and `7` is Sunday. To select all days of the week, enter an empty array.\n    - `hours` (object, required): The hours of the day during which this action will run. Hours of the day are expressed as two strings in the format `hh:mm` in `24` hour time. A start of `00:00` and an end of `24:00` means the action can run all day.\n        - start (string, required): Start time in `hh:mm` format.\n        - end (string, required): End time in `hh:mm` format.\n    - `timezone` (string, required): An ISO timezone name, such as `Europe/Madrid` or `America/New_York`. Specific offsets such as `UTC` or `UTC+1` will also work, but lack built-in DST.\n- `query` (object, optional): Object containing a query filter which gets applied to an action and determines whether the action should run.\n    - `kql` (string, required): A KQL string.\n    - `filters` (array of objects, required): Array of filter objects, as defined in the `kbn-es-query` package.\n'
});

