/**
 * Array of entries objects that define mappings between the source event fields and the values in the Elasticsearch threat index. Each entries object must contain these fields:
 *
 * - field: field from the event indices on which the rule runs
 * - type: must be mapping
 * - value: field from the Elasticsearch threat index
 *
 * You can use Boolean and and or logic to define the conditions for when matching fields and values generate alerts. Sibling entries objects are evaluated using or logic, whereas multiple entries in a single entries object use and logic. See Example of Threat Match rule which uses both `and` and `or` logic.
 *
 */
export const security_detections_api_threat_mapping = z.array(z.object({
    entries: z.array(security_detections_api_threat_mapping_entry)
})).min(1).register(z.globalRegistry, {
    description: 'Array of entries objects that define mappings between the source event fields and the values in the Elasticsearch threat index. Each entries object must contain these fields:\n\n- field: field from the event indices on which the rule runs\n- type: must be mapping\n- value: field from the Elasticsearch threat index\n  \nYou can use Boolean and and or logic to define the conditions for when matching fields and values generate alerts. Sibling entries objects are evaluated using or logic, whereas multiple entries in a single entries object use and logic. See Example of Threat Match rule which uses both `and` and `or` logic.\n'
});

